import { d3_map } from '../../../core/d3-constants';
import { Registry } from '../../../core/zc-registry';

export var HIGHLIGHT_CONTEXT = d3_map();
export var SELECTION_CONTEXT = d3_map();

HIGHLIGHT_CONTEXT.set('bar', function(chart) {
    return chart.staticPaneSVG.selectAll('g.eventgroup').selectAll('g#zcbarhighlight');
});
HIGHLIGHT_CONTEXT.set('scatter', function(chart) {
    return chart.staticPaneSVG.selectAll('g.eventgroup').selectAll('g#zcscatterhighlight');
});
HIGHLIGHT_CONTEXT.set('area', function(chart) {
    return chart.staticPaneSVG.selectAll('g.eventgroup').selectAll('g#zcareahighlight');
});

HIGHLIGHT_CONTEXT.set('nonaxis', function(chart) {
    return chart.staticPaneSVG.selectAll('g.eventgroup').selectAll('g.zcnonaxishighlight');
});

HIGHLIGHT_CONTEXT.set('geo', function(chart) {
    return chart.staticPaneSVG.selectAll('g.map-highlight');
});

SELECTION_CONTEXT.set('selection', function(chart) {
    return chart.staticPaneSVG.selectAll('g.eventgroup').selectAll('g#zcselectionhighlight');
});

export function clearHighlightContext(chart) {
    var keys = HIGHLIGHT_CONTEXT.keys();
    keys.forEach(d => {
        var context = HIGHLIGHT_CONTEXT.get(d).call(this, chart);
        context.selectAll('*').remove();
    });
}

export function clearselectionContext(chart, className) {
    var keys = SELECTION_CONTEXT.keys();
    keys.forEach(d => {
        var context = SELECTION_CONTEXT.get(d).call(this, chart);
        context.selectAll('.'+className).remove();
    });
}

Registry.setComponent('clearselectionContext', clearselectionContext);
Registry.setComponent('clearHighlightContext', clearHighlightContext);
